package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.ArrayList;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVParserTest {

    private CSVParser parser;

    @BeforeEach
    public void setUp() {
        // Mock the dependencies required to create a CSVParser instance
        // Since CSVParser constructor requires Reader and CSVFormat, we mock CSVFormat and use a StringReader
        parser = new CSVParser(new java.io.StringReader(""), mock(CSVFormat.class));
    }

    @Test
    public void testGetRecords_NoRecords() throws IOException {
        // The default getRecords() should return an empty list if no records exist
        List<CSVRecord> records = parser.getRecords();
        assertNotNull(records);
        assertTrue(records.isEmpty());
    }

    @Test
    public void testGetRecords_WithRecords() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // To test getRecords(T records) method indirectly, we use reflection to invoke private nextRecord method
        // We'll mock nextRecord to return some records and then null to simulate end of input

        // Spy the parser to stub nextRecord
        CSVParser spyParser = spy(parser);

        // Prepare CSVRecord mocks
        CSVRecord record1 = mock(CSVRecord.class);
        CSVRecord record2 = mock(CSVRecord.class);

        // Stub nextRecord to return record1, record2, then null
        when(spyParser.nextRecord())
            .thenReturn(record1)
            .thenReturn(record2)
            .thenReturn(null);

        // Use reflection to invoke the generic getRecords(T records) method
        Method getRecordsMethod = CSVParser.class.getDeclaredMethod("getRecords", List.class);
        getRecordsMethod.setAccessible(true);

        List<CSVRecord> inputList = new ArrayList<>();
        @SuppressWarnings("unchecked")
        List<CSVRecord> result = (List<CSVRecord>) getRecordsMethod.invoke(spyParser, inputList);

        assertNotNull(result);
        assertEquals(2, result.size());
        assertSame(record1, result.get(0));
        assertSame(record2, result.get(1));
        // The input list should be the same instance as the returned list
        assertSame(inputList, result);
    }

    @Test
    public void testGetRecords_ThrowsIOException() throws IOException {
        CSVParser spyParser = spy(parser);

        try {
            when(spyParser.nextRecord()).thenThrow(new IOException("IO error"));
            spyParser.getRecords();
            fail("Expected IOException");
        } catch (IOException e) {
            assertEquals("IO error", e.getMessage());
        }
    }
}
